import type { SubtitleCue } from "../types";

const timestampPattern = /(?:(\d{2,}):)?(\d{2}):(\d{2})[,.](\d{3})/;

export function timestampToSeconds(value: string): number {
  const match = value.match(timestampPattern);
  if (!match) return 0;
  const hours = Number(match[1] ?? 0);
  const minutes = Number(match[2]);
  const seconds = Number(match[3]);
  const millis = Number(match[4]);
  return hours * 3600 + minutes * 60 + seconds + millis / 1000;
}

export function secondsToTimestamp(value: number): string {
  const totalMillis = Math.max(0, Math.round(value * 1000));
  const millis = totalMillis % 1000;
  const totalSeconds = Math.floor(totalMillis / 1000);
  const seconds = totalSeconds % 60;
  const totalMinutes = Math.floor(totalSeconds / 60);
  const minutes = totalMinutes % 60;
  const hours = Math.floor(totalMinutes / 60);
  return `${String(hours).padStart(2, "0")}:${String(minutes).padStart(2, "0")}:${String(seconds).padStart(2, "0")}.${String(millis).padStart(3, "0")}`;
}

export function srtToVtt(input: string): string {
  const normalized = input.replace(/\r/g, "").trim();
  if (normalized.startsWith("WEBVTT")) return input;
  return `WEBVTT\n\n${normalized.replace(/(\d{2}:\d{2}:\d{2}),(\d{3})/g, "$1.$2")}\n`;
}

export function parseSubtitles(input: string): SubtitleCue[] {
  const vtt = srtToVtt(input)
    .replace(/\r/g, "")
    .replace(/^WEBVTT.*?(\n\n|$)/s, "")
    .trim();

  if (!vtt) return [];

  return vtt
    .split(/\n{2,}/)
    .flatMap((block) => {
      const lines = block.split("\n").filter(Boolean);
      const timeLineIndex = lines.findIndex((line) => line.includes("-->"));
      if (timeLineIndex < 0) return [];
      const [startRaw, endRaw] = lines[timeLineIndex].split("-->").map((part) => part.trim().split(/\s+/)[0]);
      const cue = {
        start: timestampToSeconds(startRaw),
        end: timestampToSeconds(endRaw),
        text: lines
          .slice(timeLineIndex + 1)
          .join("\n")
          .replace(/<[^>]+>/g, "")
      };
      return cue.end > cue.start ? [cue] : [];
    });
}

export async function loadSubtitleCues(url: string): Promise<SubtitleCue[]> {
  const response = await fetch(url);
  if (!response.ok) throw new Error(`Subtitle request failed with ${response.status}`);
  return parseSubtitles(await response.text());
}

export function activeCue(cues: SubtitleCue[], currentTime: number, delay: number): SubtitleCue | undefined {
  const adjusted = currentTime + delay;
  return cues.find((cue) => adjusted >= cue.start && adjusted <= cue.end);
}
