import type { MkvPlayerMetadata, MkvPlayerSource, PlaybackStrategy, ServerConfig, SubtitleTrack } from "../types";

export type ResolvedSource = {
  objectUrl?: string;
  originalUrl?: string;
  videoUrl: string;
  strategy: PlaybackStrategy;
  metadata?: Partial<MkvPlayerMetadata>;
};

const mkvLike = /\.(mkv|webm)(\?|#|$)/i;

export function sourceToUrl(src: MkvPlayerSource): { url: string; objectUrl?: string; isObject: boolean } {
  if (typeof src === "string") {
    const url = typeof window === "undefined" ? src : new URL(src, window.location.href).toString();
    return { url, isObject: false };
  }

  const objectUrl = URL.createObjectURL(src);
  return { url: objectUrl, objectUrl, isObject: true };
}

export async function resolvePlaybackSource(src: MkvPlayerSource, server?: ServerConfig): Promise<ResolvedSource> {
  const source = sourceToUrl(src);
  const shouldUseServer = server?.enabled && typeof src === "string";

  if (!shouldUseServer || !server?.baseUrl) {
    if (/\.m3u8(\?|#|$)/i.test(source.url)) {
      return {
        objectUrl: source.objectUrl,
        originalUrl: typeof src === "string" ? src : undefined,
        videoUrl: source.url,
        strategy: "server-hls"
      };
    }

    return {
      objectUrl: source.objectUrl,
      originalUrl: typeof src === "string" ? src : undefined,
      videoUrl: source.url,
      strategy: "native"
    };
  }

  try {
    if (server.delivery === "hls") {
      const sessionUrl = new URL("/hls/session", server.baseUrl);
      sessionUrl.searchParams.set("url", source.url);
      const response = await fetch(sessionUrl);
      if (!response.ok) throw new Error(`HLS session request failed with ${response.status}`);
      const session = (await response.json()) as { playlistUrl: string; metadata?: Partial<MkvPlayerMetadata> };
      return {
        originalUrl: source.url,
        videoUrl: new URL(session.playlistUrl, server.baseUrl).toString(),
        strategy: "server-hls",
        metadata: { ...session.metadata, strategy: "server-hls" }
      };
    }

    const metadataUrl = new URL("/metadata", server.baseUrl);
    metadataUrl.searchParams.set("url", source.url);
    const response = await fetch(metadataUrl);
    if (!response.ok) throw new Error(`Metadata request failed with ${response.status}`);
    const metadata = (await response.json()) as Partial<MkvPlayerMetadata>;
    const streamUrl = new URL("/stream", server.baseUrl);
    streamUrl.searchParams.set("url", source.url);
    streamUrl.searchParams.set("mode", "auto");
    if (server.delivery) streamUrl.searchParams.set("delivery", server.delivery);
    return {
      originalUrl: source.url,
      videoUrl: streamUrl.toString(),
      strategy: metadata.strategy ?? "server-remux",
      metadata
    };
  } catch (cause) {
    if (shouldUseServer) {
      throw cause instanceof Error ? cause : new Error("Server-assisted source resolution failed");
    }
    return {
      objectUrl: source.objectUrl,
      originalUrl: typeof src === "string" ? src : undefined,
      videoUrl: source.url,
      strategy: "native",
      metadata: {
        strategy: "native"
      }
    };
  }
}

export function buildSubtitleUrl(server: ServerConfig | undefined, src: MkvPlayerSource, track: SubtitleTrack): string | undefined {
  if (track.src) return track.src;
  if (!server?.enabled || !server.baseUrl || typeof src !== "string" || track.index == null) return undefined;

  const resolved = sourceToUrl(src);
  const url = new URL("/subtitles", server.baseUrl);
  url.searchParams.set("url", resolved.url);
  url.searchParams.set("track", String(track.index));
  url.searchParams.set("format", "vtt");
  return url.toString();
}

export function getNativeSupport(url: string): "probably" | "maybe" | "" {
  if (typeof document === "undefined") return "";
  const video = document.createElement("video");
  if (/\.mp4(\?|#|$)/i.test(url)) return video.canPlayType("video/mp4");
  if (/\.webm(\?|#|$)/i.test(url)) return video.canPlayType("video/webm");
  if (/\.mkv(\?|#|$)/i.test(url)) return video.canPlayType("video/x-matroska") || video.canPlayType("video/webm");
  return "";
}
